import React, { useMemo, useState } from 'react';
import {
  Button,
  Input,
  Select,
  Modal,
  Checkbox,
  addToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { masterService } from '../../../services/master/masterService';
import type { CustomerGroupDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import {
  CatalogFormFooter,
  CatalogListPagination,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogPagination,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
} from '../../../components/catalog';
import {
  flattenCustomerGroupTree,
  CUSTOMER_TYPE_LABELS,
  MAX_CUSTOMER_GROUP_LEVEL,
  customerGroupRowIndent,
  buildCustomerTypeOptionsFromGroups,
} from '../../../utils/customerGroupTree';
import styles from '../../../styles/erpPage.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-nhom-doi-tuong';

type FormErrors = Partial<Record<'code' | 'name' | 'customerType', string>>;

const NhomDoiTuongPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<CustomerGroupDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [serverTotalCount, setServerTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<CustomerGroupDto | null>(null);
  const [form, setForm] = useState<Partial<CustomerGroupDto>>({ isActive: true, customerType: 'Both' });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [deleteCustomerGroupId, setDeleteCustomerGroupId] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const initFormName = modalOpen && editing ? 'edit-customer-group' : 'create-customer-group';
  const { customerTypeOptions: initTypeOptions } = useVoucherInitData(initFormName);
  const customerTypeOpts = useMemo(
    () => buildCustomerTypeOptionsFromGroups(items, initTypeOptions),
    [items, initTypeOptions],
  );

  const isSearchMode = search.trim().length > 0;
  const {
    page: serverPage,
    setPage: setServerPage,
    pageSize: serverPageSize,
    setPageSize: setServerPageSize,
    resetPage: resetServerPage,
  } = useCatalogListPaging();

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService
        .getCustomerGroups({
          search: search || undefined,
          page: isSearchMode ? serverPage : 1,
          pageSize: isSearchMode ? serverPageSize : 500,
        })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setServerTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải nhóm đối tượng', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, isSearchMode, serverPage, serverPageSize, reloadKey, dispatch]);

  const groupOpts = useMemo(
    () => items
      .filter(g => !editing || g.customerGroupId !== editing.customerGroupId)
      .filter(g => (g.level ?? 1) < MAX_CUSTOMER_GROUP_LEVEL)
      .map(g => ({
        value: String(g.customerGroupId),
        label: `${'  '.repeat((g.level ?? 1) - 1)}${g.code} — ${g.name}`,
      })),
    [items, editing],
  );

  const displayRows = useMemo(
    () => (isSearchMode ? items : flattenCustomerGroupTree(items)),
    [items, isSearchMode],
  );

  const clientPaging = useCatalogPagination(displayRows);

  const page = isSearchMode ? serverPage : clientPaging.page;
  const setPage = isSearchMode ? setServerPage : clientPaging.setPage;
  const pageSize = isSearchMode ? serverPageSize : clientPaging.pageSize;
  const setPageSize = isSearchMode ? setServerPageSize : clientPaging.setPageSize;
  const totalCount = isSearchMode ? serverTotalCount : clientPaging.totalCount;
  const tableRows = isSearchMode ? items : clientPaging.pageItems;

  const resetPage = () => {
    resetServerPage();
    clientPaging.resetPage();
  };

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã nhóm';
    if (!form.name?.trim()) next.name = 'Nhập tên nhóm';
    if (!form.customerType?.trim()) next.customerType = 'Chọn loại nhóm';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = (parentCustomerGroupId?: string) => {
    setEditing(null);
    setForm({
      isActive: true,
      customerType: 'Both',
      parentCustomerGroupId: parentCustomerGroupId ?? undefined,
    });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: CustomerGroupDto) => {
    setEditing(row);
    setForm({ ...row, parentCustomerGroupId: row.parentCustomerGroupId ?? undefined });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateCustomerGroup(editing.customerGroupId, form);
      else await masterService.createCustomerGroup(form);
      markClean();
      dispatch(addToast({
        message: editing ? 'Cập nhật nhóm đối tượng thành công' : 'Tạo nhóm đối tượng thành công',
        type: 'success',
      }));
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
    });
  };

  const refresh = () => setReloadKey(k => k + 1);

  const handleDelete = async (customerGroupId: string) => {
    try {
      await masterService.deleteCustomerGroup(customerGroupId);
      dispatch(addToast({ message: 'Xóa nhóm đối tượng thành công', type: 'success' }));
      setDeleteCustomerGroupId(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-users" /> Nhóm đối tượng</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={() => openAdd()} data-testid={`${TEST_ID}-add-btn`}>
            <i className="fas fa-plus" /> Thêm nhóm
          </Button>
        </div>
      </div>
      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách nhóm đối tượng"
        showTableLoading={showTableLoading}
        footer={
          <CatalogListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={setPage}
            onPageSizeChange={setPageSize}
          />
        }
        filters={
          <>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <Input
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={e => setSearchDraft(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
              />
            </div>
            <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} />
          </>
        }
      >
        {displayRows.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy nhóm phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên</th>
                  <CatalogCompanyTh />
                  <th>Loại</th>
                  <th>Nhóm cha</th>
                  <th>Cấp</th>
                  <th>Số ĐT</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {tableRows.map(r => {
                  const indent = customerGroupRowIndent(r.level);
                  return (
                    <tr key={r.customerGroupId}>
                      <td style={indent > 0 ? { paddingLeft: indent } : undefined}>
                        <code>{r.code}</code>
                      </td>
                      <td>{r.name}</td>
                    <CatalogCompanyTd label={r.companyName} />
                      <td>
                        <span className={styles.tagDefault}>
                          {CUSTOMER_TYPE_LABELS[r.customerType ?? 'Both'] ?? r.customerType ?? '—'}
                        </span>
                      </td>
                      <td>{r.parentName ?? '—'}</td>
                      <td>{r.level ?? '—'}</td>
                      <td>{r.customerCount ?? 0}</td>
                      <td>
                        <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                          {r.isActive ? 'Dùng' : 'Ngưng'}
                        </span>
                      </td>
                      <td className={styles.colActions}>
                        <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Sửa">
                          <i className="fas fa-edit" />
                        </button>
                        {(r.level ?? 1) < MAX_CUSTOMER_GROUP_LEVEL && (
                          <button
                            type="button"
                            className={styles.actionBtn}
                            onClick={() => openAdd(r.customerGroupId)}
                            title="Thêm con"
                          >
                            <i className="fas fa-plus" />
                          </button>
                        )}
                        <button
                          type="button"
                          className={`${styles.actionBtn} ${styles.actionBtnDanger}`}
                          onClick={() => setDeleteCustomerGroupId(r.customerGroupId)}
                          title="Xóa"
                        >
                          <i className="fas fa-trash" />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </CatalogListShell>

      <Modal isOpen={modalOpen} onClose={closeFormModal} title={editing ? 'Sửa nhóm đối tượng' : 'Thêm nhóm đối tượng'}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-parentCustomerGroupId`}>
              <label className={styles.label}>Nhóm cha</label>
              <Select
                value={form.parentCustomerGroupId != null ? String(form.parentCustomerGroupId) : ''}
                placeholder="— Cấp 1 —"
                className={selectPlaceholderClass(
                  form.parentCustomerGroupId != null ? String(form.parentCustomerGroupId) : '',
                )}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, parentCustomerGroupId: e.target.value || undefined }));
                }}
                options={groupOpts}
              />
            </div>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã nhóm *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên nhóm *</label>
                <Input
                  value={form.name ?? ''}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-customerType`}>
              <label className={styles.label}>Loại *</label>
              <Select
                value={form.customerType ?? 'Both'}
                error={errors.customerType}
                onChange={e => {
                  markDirty();
                  clearFieldError('customerType');
                  setForm(f => ({ ...f, customerType: e.target.value }));
                }}
                options={customerTypeOpts}
              />
            </div>
          </div>
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
          />
        </div>
      </Modal>

      <LeaveConfirmModal {...leaveConfirmModalProps} />

      <Modal isOpen={deleteCustomerGroupId != null} onClose={() => setDeleteCustomerGroupId(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa nhóm đối tượng này?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteCustomerGroupId(null)}>Hủy</Button>
          <Button
            variant="primary"
            onClick={() => deleteCustomerGroupId != null && handleDelete(deleteCustomerGroupId)}
          >
            Xóa
          </Button>
        </div>
      </Modal>
    </div>
  );
};

export default NhomDoiTuongPage;
